import os

def print_loudest_100_files():
    files = [f for f in os.listdir('.') if f.endswith('.txt') and os.path.getsize(f) > 100]

    for f in sorted(files, key=lambda f: os.path.getsize(f), reverse=True):
        os.chmod(f, 0o777)
        with open(f) as file:
            print(os.path.getsize(f), f)
            for i in range(1, 101):
                for line in file:
                    if line.startswith(str(i)):
                        print(line, end='')

