Bored with tasks? Let's talk programming: 1) Write a binary tree. 2) Write a binary tree list. 3) Write a clicker game. 4) Write a game using only a 1-bit canvas. 5) Write a compiler for a language without branches. Write a colouring algorithm. Game: stop the ball from falling and staying alive. Ball bounces off shapes; if a bounce is not on a shape then lose a life. Use load and save to preserve game progress.import re

class Shader:
    regex = re.compile(r"(\w+)\s+(\w+)\s+(.*)")
    loads = []
    saves = []

    def __init__(self, src):
        matches = self.regex.match(src)
        if not matches:
            raise ValueError("Could not parse shader")
        self.type = matches[1]
        self.name = matches[2]
        self.body = matches[3]

    def compile(self):
        if self.type == "vertex":
            return self.body
        elif self.type == "fragment":
            return self.body
        else:
            raise ValueError("Invalid shader type")

    def add_load(self, mesh):
        self.loads.append(mesh)

    def add_save(self, mesh):
        self.saves.append(mesh)

    def load(self, mesh):
        self.add_load(mesh)

    def save(self, mesh):
        self.add_save(mesh)

