import tarfile
import os
def extract_all_tars(path):
    for root, dirs, files in os.walk(path):
        for file in files:
            if file.endswith('.tar'):
                tar = tarfile.open(os.path.join(root, file))
                tar.extractall(path='../')
                tar.close()
